1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells due to underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as a still life", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
18	  });
19	  it.todo("should transform a vertical blinker into a horizontal blinker");
20	  it.todo("should let a center cell survive when it has 2 live neighbors in a 3-in-row with extra");
21	  it.todo("should kill the center cell of a full 3x3 due to overpopulation");
22	  it.todo("should create a new cell via reproduction in an L-shape");
23	});
24

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (isAlive && neighbors === 2);
13	
14	export const nextGeneration = (cells: Cell[]): Cell[] => {
15	  const liveCells = new Map<string, Cell>(
16	    cells.map((cell) => [cellKey(cell[0], cell[1]), cell]),
17	  );
18	
19	  const candidates = new Map<string, Cell>();
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const cell: Cell = [x + dx, y + dy];
23	      candidates.set(cellKey(cell[0], cell[1]), cell);
24	    }
25	    candidates.set(cellKey(x, y), [x, y]);
26	  }
27	
28	  const countLiveNeighbors = (x: number, y: number): number =>
29	    NEIGHBOR_OFFSETS.reduce(
30	      (count, [dx, dy]) => count + (liveCells.has(cellKey(x + dx, y + dy)) ? 1 : 0),
31	      0,
32	    );
33	
34	  const result: Cell[] = [];
35	  for (const [key, cell] of candidates) {
36	    const isAlive = liveCells.has(key);
37	    if (survives(isAlive, countLiveNeighbors(cell[0], cell[1]))) {
38	      result.push(cell);
39	    }
40	  }
41	  return result;
42	};
